-- 주의: image_url은 placehold.co 플레이스홀더입니다. 실제 3D 배지 아트로 교체 필요.


-- 5개 POI에 대응 배지 연결 (poi.linked_badge_id)
UPDATE public.poi SET linked_badge_id = (SELECT id FROM public.badges WHERE name = '남산 정복자' LIMIT 1) WHERE name = '남산 N서울타워';
UPDATE public.poi SET linked_badge_id = (SELECT id FROM public.badges WHERE name = '뚝섬 라이더' LIMIT 1) WHERE name = '뚝섬 한강공원 자전거 기점';
UPDATE public.poi SET linked_badge_id = (SELECT id FROM public.badges WHERE name = '북악스카이웨이 클라이머' LIMIT 1) WHERE name = '북악스카이웨이 팔각정';
UPDATE public.poi SET linked_badge_id = (SELECT id FROM public.badges WHERE name = '청계산 완주자' LIMIT 1) WHERE name = '청계산 옛골 입구';
UPDATE public.poi SET linked_badge_id = (SELECT id FROM public.badges WHERE name = '광나루 라이더' LIMIT 1) WHERE name = '광나루 한강공원 자전거 대여소';
